import Vue from 'vue';
import VueRouter from 'vue-router';
import Login from './views/LoginPage.vue';
import Layout from './views/LayoutPage.vue';
import StudentInfo from './views/StudentInfo.vue';
import CourseSelect from './views/CourseSelect.vue';
import MyCourses from './views/MyCourses.vue';

Vue.use(VueRouter);

const routes = [
  {
    path: '/',
    name: 'Login',
    component: Login
  },
  {
    path: '/',
    component: Layout,
    redirect: '/students',
    children: [
      {
        path: 'students',
        name: 'Students',
        component: StudentInfo
      },
      {
        path: 'course-select',
        name: 'CourseSelect',
        component: CourseSelect
      },
      {
        path: 'my-courses',
        name: 'MyCourses',
        component: MyCourses
      }
    ]
  }
];

const router = new VueRouter({
  mode: 'history',
  base: process.env.BASE_URL,
  routes
});

// 简单的路由守卫，未登录拦截
router.beforeEach((to, from, next) => {
  const isLogin = localStorage.getItem('token'); // 实际项目中应检查 token
  if (to.path !== '/' && !isLogin) {
    // 演示用：如果没有 token 但访问内部页面，暂时放行以便你查看效果
    // 真实场景请开启: next('/'); 
    next(); 
  } else {
    next();
  }
});

export default router;
